def afterstate_value_iteration(
    states: list,
    actions: dict,
    afterstate_map: dict,
    env_dynamics: dict,
    gamma: float,
    theta: float = 0.0001,
    max_iterations: int = 1000
) -> tuple:
    # Initialize all afterstate values to zero
    afterstate_values = {aft: 0.0 for aft in env_dynamics}

    for _ in range(max_iterations):
        delta = 0.0
        new_values = {}

        for afterstate, transitions in env_dynamics.items():
            v = 0.0
            for prob, reward, next_state in transitions:
                next_acts = actions.get(next_state, [])
                if next_acts:
                    best_next = max(
                        afterstate_values.get(afterstate_map[(next_state, a)], 0.0)
                        for a in next_acts
                    )
                else:
                    # Terminal state — no future value
                    best_next = 0.0
                v += prob * (reward + gamma * best_next)
            new_values[afterstate] = v
            delta = max(delta, abs(v - afterstate_values.get(afterstate, 0.0)))

        afterstate_values = new_values
        if delta < theta:
            break

    # Round values to 4 decimal places
    afterstate_values = {k: round(v, 4) for k, v in afterstate_values.items()}

    # Extract greedy policy — tie-break by lexicographically smallest action
    policy = {}
    for state in states:
        state_actions = actions.get(state, [])
        if state_actions:
            policy[state] = min(
                state_actions,
                key=lambda a: (
                    -afterstate_values.get(afterstate_map.get((state, a)), 0.0),
                    a
                )
            )

    return afterstate_values, policy
